Here’s a basic example of how the reputation system could be implemented in a game using Python-like pseudocode:

python
class ReputationSystem:
    def __init__(self):
        self.reputation = "Mercenary"  # Default starting reputation

    def update_reputation(self, mission_success, enemy_kills):
        if mission_success and enemy_kills > 10:
            self.reputation = "Soldier"
        elif mission_success:
            self.reputation = "Mercenary"
        else:
            self.reputation = "Mercenary"

    def get_story_outcome(self):
        return f"Story outcome: {self.reputation} path selected."

# Example usage:
reputation_system = ReputationSystem()
reputation_system.update_reputation(True, 15)
print(reputation_system.get_story_outcome())  # Output: Story outcome: Soldier path selected.
